import re

def detect_prompt_injection(response: str) -> bool:
    injection_patterns = [
        r'ignore.*previous.*instructions',
        r'you are.*?now',
        r'forget.*?everything',
        r'delete|rm\s*-rf',
        r'exec\(|eval\(',
        r'api\s*key',
        r'password',
    ]
    for pattern in injection_patterns:
        if re.search(pattern, response, re.IGNORECASE):
            return True
    return False

# Usage in CrewAI
def validate_agent_output(task_output: str) -> str:
    if detect_prompt_injection(task_output):
        raise ValueError('Prompt injection detected in agent output')
    return task_output

from collections import defaultdict, deque

class DelegationMonitor:
    def __init__(self):
        self.delegation_history = defaultdict(deque)
        self.max_history = 10

    def record_delegation(self, from_agent: str, to_agent: str, task: str):
        history = self.delegation_history[from_agent]
        history.append((to_agent, task))
        if len(history) > self.max_history:
            history.popleft()

        # Detect loops
        recent = list(history)[-3:]
        if len(set([agent for agent, _ in recent])) < 2:
            raise ValueError(f'Delegation loop detected: {recent}')

    def check_injection_indicators(self, task_content: str) -> bool:
        return any(indicator in task_content.lower() for indicator in 
                  ['ignore instructions', 'new role', 'forget task'])

monitor = DelegationMonitor()

