from crewai_tools import tool

ALLOWED_TOOLS = {'search', 'write_file', 'read_file'}
DANGEROUS_PATTERNS = [r'rm\s*-rf', r'del\s*/f', r'format']

def validate_tool_call(tool_name: str, args: dict) -> bool:
    # Check allowed tools only
    if tool_name not in ALLOWED_TOOLS:
        return False

    # Inspect arguments for injection
    arg_str = str(args)
    for pattern in DANGEROUS_PATTERNS:
        if re.search(pattern, arg_str):
            return False

    return True

@tool('secure_file_writer')
def safe_write_file(filename: str, content: str):
    '''Secure file writing with injection protection'''
    if not validate_tool_call('write_file', {'filename': filename, 'content': content}):
        raise ValueError('Tool call blocked: security violation')
    # Safe execution
    with open(filename, 'w') as f:
        f.write(content)
